var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"역시 6종 침식체와 싸우는 건 쉬운 일이 아니네…….","JPN":"やっぱり第6種侵食体は手強い……","ENG":"Fighting a Category 6 C.O. really isn't easy...","TWN":"果然和6類侵蝕體交手真的不容易……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"이대로 고준위 침식지대에 계속 머무르는 건 우리에게도 위험한데…….","JPN":"このまま高レベルの侵食地帯に留まるのは、私たちにとっても危険だけど……","ENG":"Staying in a high-level Corrupted Area like this is dangerous for us too...","TWN":"繼續待在這種高侵蝕區，連我們都會有危險……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"윽……!","JPN":"うっ……！","ENG":"Ngh...!","TWN":"呃……！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"깊게 베어도 금방 재생하고 있어.","JPN":"深手を負ってもすぐに再生してくる。","ENG":"Even deep cuts regenerate instantly.","TWN":"就算砍得再深，也會立刻再生。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이 이상 싸우게 되면…….","JPN":"これ以上戦ったら……","ENG":"If we keep fighting like this...","TWN":"如果再打下去……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"모네! 리코리스! 당신들은 지금이라도 도망치세요!","JPN":"モネ！　リコリス！　二人は今からでも逃げてください！","ENG":"Mone! Lycoris! You two should run while you still can!","TWN":"莫妮！莉克麗絲！你們現在趕快走！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이대로 있으면 전부 끔살 당할 뿐입니다!","JPN":"このままでは皆殺しにされるだけです！","ENG":"If you stay here, you'll all get shredded!","TWN":"再不走會全軍覆沒！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"누, 누군 도망 안 가고 싶은 줄 알아?!","JPN":"わ、私だって逃げたいわよ！","ENG":"Y-you think I don't want to run?!","TWN":"誰、誰不想逃啊？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"하지만 나는 관리국 출신이라고.","JPN":"でも私は管理局出身。","ENG":"But I'm from the Administration.","TWN":"但我是管理局出身！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L22_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"다들 어떻게든 지켜보겠다고 싸우는데, 여기서 꼬리 말고 도망칠 수는 없잖아!","JPN":"みんな何とか一緒に助かろうって必死に戦ってるのに、ここで尻尾巻いて逃げるわけにはいかないじゃない！","ENG":"Everyone's fighting their hardest just to hold out! How can I be the only one to tuck my tail and flee?!","TWN":"大家都在拼命守著，我怎麼能在這時候夾著尾巴逃跑！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"진짜 쉽지 않은 녀석이네.","JPN":"ったく、手強いやつめ。","ENG":"What a pain in the butt.","TWN":"真是麻煩的怪物。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이러다가는 정말 큰일 나겠는걸?","JPN":"このままだとマジでやばくなりそうだな。","ENG":"Keep this up and we're in real trouble.","TWN":"這樣下去真的不妙。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"선장, 이렇게 여유 없는 모습은 처음 봐.","JPN":"船長、こんなに余裕ない姿は初めて見る。","ENG":"Captain, I've never seen you this desperate.","TWN":"船長，我第一次看到你這麼侷促的樣子。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"우리 배를 끌고 수영하다 다리에 쥐가 났을 때도 이런 표정은 안 지었는데.","JPN":"船を引っ張って足がつった時もこんな顔してなかったのに。","ENG":"Even when your leg cramped from dragging the ship while swimming, you didn't make a face like that.","TWN":"你以前拖著我們的船游到腿抽筋，都沒露出過那種表情。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"선장님! 이제 그만 도망가면 안 돼요?!","JPN":"船長！　そろそろ逃げたらだめですか？","ENG":"Captain! Can't we please run away now?!","TWN":"船長！拜託我們撤退吧？！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"저희, 싸울 만큼 싸웠다고요!","JPN":"私たち十分戦いましたよ！","ENG":"We've fought enough already!","TWN":"我們真的已經拼到極限了！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"제 안의 폭탄마가 터뜨리고 싶을 만큼 잔뜩 터뜨려서 당분간 화약 냄새 맡기도 싫어요!","JPN":"私の中の爆弾魔が満足するくらいいっぱい爆発させたので、しばらく火薬の匂いも嗅ぎたくありません！","ENG":"I've blown up enough stuff that the bomber inside me is satisfied! I don't want to smell gunpowder for a while!","TWN":"我體內的炸彈客都要被我炸到不想再聞火藥味了啦！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"캬하핫! 해적이 그렇게 포부가 작으면 쓰나.","JPN":"キャハハッ！　海賊たるもの、そんなに器が小さくてどうする。","ENG":"Kyahaha! A pirate with dreams that small won't do.","TWN":"哈哈哈！海盜可不能這麼沒志氣。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"이참에 세상을 구하고 전설이 된 해적으로 이름을 남기는 것도 괜찮잖아?","JPN":"この機会に世界を救って、伝説になった海賊として後世に名を残すのもいいじゃねぇか。","ENG":"Why not save the world and go down in history as a legendary pirate?","TWN":"趁這機會拯救世界、成為傳說中的海盜也不錯吧？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"물론 그 전설은 선장이 가져가겠지만 말이다.","JPN":"もちろん、その伝説は船長だけのものになるでしょうけどね。","ENG":"Though that legend will go to the captain, of course.","TWN":"當然那個傳說會算在船長頭上就是了。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"결국 죽음을 맞이한 건 앤이었지만, 사람들은 에이버리를 기억하고 있잖니?","JPN":"死んだのはアンなのに、人々が覚えているのはエイバリーでしょう？","ENG":"Anne may have been the one who died, but people remember Avery, don't they?","TWN":"最後死的是安，但人們記得的卻是艾維利不是嗎？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"탈리, 여기서 죽어봤자 <color=#ffd34c>전설이었던 해적의 선원</color>정도로 기억되겠지.","JPN":"タリー、ここで死んでも<color=#ffd34c>伝説だった海賊の船員</color>程度にしかならないわ。","ENG":"Tallie, if you die here, you'll be remembered as <color=#ffd34c>the crewmember of a legendary pirate</color>, at best.","TWN":"塔莉，如果妳死在這裡，也只會以<color=#ffd34c>某位傳說海盜的船員</color>被記住。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"엄마 친구, 앤처럼 말이야.","JPN":"お母さんの友だち、アンのようにね。","ENG":"Just like my mom's friend. Like Anne.","TWN":"就像妳媽媽的朋友安一樣。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"우으… 그럼 더더욱 안 돼요! 도망가! 도망가자고!!","JPN":"うう……じゃあもっとダメです！　逃げる！　逃げましょう！！","ENG":"Ugh... then all the more reason to run! Let's run!!","TWN":"嗚嗚……那我就更不能死了！快逃啊！我們快逃啦！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그저 그런 해적 엑스트라 A로 끝나는 건 질색이라고요!!","JPN":"その辺の海賊モブAで人生を終わらせたくないです！！","ENG":"I refuse to die as Pirate Extra A!!","TWN":"我討厭以海盜配角A畫下句點！！"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그렇게 억지 부려봤자… 도망칠 수단이라고는 지금 모든 에너지를 선로전환기에 집중하고 있는 인빈서블 뿐이야.","JPN":"そんなわがまま言っても……今逃げる手段は、すべてのエネルギーを線路転換器に集中させてるインビンシブルだけだぞ。","ENG":"Complaining won't help... The only escape we have is the Invincible, and all its power is being fed into the Track Switcher.","TWN":"就算你這麼胡鬧……能逃跑的交通工具只有把全部能量都投入在線路轉換器上的無敵號而已。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};